Here's an example program in C# that has a form with 5 text inputs and can print it in a report:

using System;
using System.Data;
using System.Drawing;
using System.Windows.Forms;
using System.IO;

namespace ReportGenerator
{
    public partial class Form1 : Form
    {
        public Form1()
        {
            InitializeComponent();
        }

        private void btnPrint_Click(object sender, EventArgs e)
        {
            // Create a new report document
            ReportDocument report = new ReportDocument();

            // Set the report's title
            report.AddTitle("Report");

            // Add a new section to the report
            ReportSection section = report.AddSection();

            // Add a table to the section
            ReportTable table = section.AddTable();

            // Add columns to the table
            table.AddColumn("Name");
            table.AddColumn("Address");
            table.AddColumn("City");
            table.AddColumn("State");
            table.AddColumn("Zip Code");

            // Add a row to the table with the values from the text inputs
            ReportRow row = table.AddRow();
            row.AddCell(txtName.Text);
            row.AddCell(txtAddress.Text);
            row.AddCell(txtCity.Text);
            row.AddCell(txtState.Text);
            row.AddCell(txtZipCode.Text);

            // Generate the report
            string reportHtml = report.GenerateHtml();

            // Display the report in a web browser control
            webBrowser1.DocumentText = reportHtml;
        }
    }
}

This program creates a new report document, adds a section and table to it, and populates the table with the values entered in the text inputs. It then generates an HTML representation of the report and displays it in a web browser control.
